class DownBlock(nn.Module):
    """
    Encoder block: n_res ResBlocks → optional attention → spatial downsampling.
    Returns (output, [h1, h2, ...]) where h_i are skip tensors before downsampling.
    """

    def __init__(self, in_ch: int, out_ch: int, time_dim: int,
                 n_res: int = 2, use_attn: bool = False, downsample: bool = True):
        super().__init__()
        self.resnets = nn.ModuleList([
            ResBlock(in_ch if i == 0 else out_ch, out_ch, time_dim)
            for i in range(n_res)
        ])
        self.attn = SelfAttentionBlock(out_ch) if use_attn else None
        # Stride-2 conv for downsampling (avoids aliasing artifacts vs AvgPool)
        self.down = nn.Conv2d(out_ch, out_ch, 3, stride=2, padding=1) if downsample else None

    def forward(self, x, t_emb):
        skips = []
        for resnet in self.resnets:
            x = resnet(x, t_emb)
            skips.append(x)
        if self.attn is not None:
            x = self.attn(x)
            skips[-1] = x       # update last skip after attention
        if self.down is not None:
            x = self.down(x)
        return x, skips


class UpBlock(nn.Module):
    """
    Decoder block: upsample → concatenate skip → n_res ResBlocks → optional attention.
    """

    def __init__(self, in_ch: int, skip_ch: int, out_ch: int, time_dim: int,
                 n_res: int = 2, use_attn: bool = False, upsample: bool = True):
        super().__init__()
        self.up = nn.Sequential(
            nn.Upsample(scale_factor=2, mode="nearest"),
            nn.Conv2d(in_ch, in_ch, 3, padding=1)
        ) if upsample else None

        # Each ResBlock takes (in_ch + skip_ch) on first block due to concatenation
        self.resnets = nn.ModuleList()
        for i in range(n_res):
            block_in  = (in_ch + skip_ch) if i == 0 else out_ch
            self.resnets.append(ResBlock(block_in, out_ch, time_dim))

        self.attn = SelfAttentionBlock(out_ch) if use_attn else None

    def forward(self, x, skips, t_emb):
        if self.up is not None:
            x = self.up(x)
        for i, resnet in enumerate(self.resnets):
            if i == 0 and skips:
                x = torch.cat([x, skips.pop()], dim=1)    # concatenate skip
            x = resnet(x, t_emb)
        if self.attn is not None:
            x = self.attn(x)
        return x

from torch.utils.checkpoint import checkpoint


class CheckpointedResBlock(ResBlock):
    """ResBlock with activation checkpointing — halves peak memory."""

    def forward(self, x: torch.Tensor, t_emb: torch.Tensor) -> torch.Tensor:
        return checkpoint(
            super().forward,
            x, t_emb,
            use_reentrant=False,   # safer with autograd hooks
        )
